    int[] cols = new int[grid[0].length];

    for (int i = 0; i < grid.length; i++) {
        for (int j = 0; j < grid[i].length; j++) {
            rows[i] = Math.max(rows[i], grid[i][j]);
            cols[j] = Math.max(cols[j], grid[i][j]);
        }
